    html += '<h4 style="font-size:12px;color:#475569;margin:6px 0 4px;">实验检查清单</h4><ul style="font-size:11px;color:#475569;padding-left:20px;">';
    for (var i = 0; i < checklist.length; i++) {
      html += '<li>' + checklist[i] + '</li>';
