  }
  // Fallback for other field structures
  if (s.current_sota) html += '<div style="margin-bottom:4px;"><b>当前 SOTA:</b> ' + s.current_sota + '</div>';
  if (s.gap) html += '<div style="margin-bottom:4px;"><b>差距:</b> ' + s.gap + '</div>';
