      var dir = d.direction || d.title || ('路径 ' + (i+1));
      var gain = d.expected_gain || '';
      var diff = d.difficulty || '';
      var items = d.action_items || [];
      html += '<li style="margin-bottom:6px;"><b>' + dir + '</b>';
      if (gain) html += '<br><span style="color:#16a34a;font-size:11px;">预期增益: ' + gain + '</span>';
      if (diff) html += ' <span style="color:#f59e0b;font-size:11px;">难度: ' + diff + '</span>';
      if (items.length > 0) {
        html += '<ul style="font-size:11px;color:#64748b;padding-left:20px;">';
        for (var j = 0; j < items.length; j++) html += '<li>' + items[j] + '</li>';
        html += '</ul>';
      }
      html += '</li>';
    }
    html += '</ul>';
  }
  // Degradation paths
  var degr = opts.degradation_paths || [];
  if (degr.length > 0) {
    html += '<h4 style="font-size:12px;color:#475569;margin:6px 0 4px;">降级路径 (' + degr.length + ')</h4><ul style="list-style:none;padding:0;">';
    for (var i = 0; i < degr.length; i++) {
      var d = degr[i];
      html += '<li style="margin-bottom:4px;font-size:11px;"><b>' + (d.path||'') + '</b>';
      if (d.trade_off) html += ' <span style="color:#ef4444;">代价: ' + d.trade_off + '</span>';
      if (d.survival_rate) html += ' <span style="color:#64748b;">存活率: ' + d.survival_rate + '</span>';
      html += '</li>';
    }
    html += '</ul>';
  }
  // Risk mitigation
  var risks = opts.risk_mitigation || [];
  if (risks.length > 0) {
    html += '<h4 style="font-size:12px;color:#475569;margin:6px 0 4px;">风险缓解</h4><ul style="font-size:11px;color:#475569;padding-left:20px;">';
    for (var i = 0; i < risks.length; i++) html += '<li>' + risks[i] + '</li>';
    html += '</ul>';
  }
  if (opts.summary) html += '<div style="margin-top:4px;">' + opts.summary + '</div>';
  if (!html) html = '<div style="color:#94a3b8">无优化建议</div>';
  document.getElementById('optimizationContent').innerHTML = html;
}

function renderTrace(caseId) {
  fetch('/api/v1/research/' + caseId + '/trace').then(function(r) { return r.json(); }).then(function(trace) {
    if (!trace || trace.length === 0) return;
    document.getElementById('traceSection').style.display = '';
    var html = '';
    for (var i = 0; i < trace.length; i++) {
      var ev = trace[i];
      var node = ev.node || ev.step || '';
      var msg = ev.output_summary ? JSON.stringify(ev.output_summary) : (ev.input_summary ? JSON.stringify(ev.input_summary) : '');
      var prov = ev.provider || '';
      var cls = prov === 'heuristic' ? 'color:#f59e0b' : 'color:#475569';
      html += '<div style="padding:3px 0;border-bottom:1px solid #f8fafc;font-size:11px;">';
      html += '<span style="color:#94a3b8;">[' + (i+1) + ']</span> ';
      html += '<b style="' + cls + '">' + node + '</b> ';
      if (prov) html += '<span style="color:#cbd5e1;">(' + prov + ')</span> ';
      if (ev.elapsed_s) html += '<span style="color:#94a3b8;">' + ev.elapsed_s + 's</span> ';
      if (msg) html += '<span style="color:#64748b;">' + msg.substring(0, 120) + '</span>';
      html += '</div>';
    }
    document.getElementById('traceContent').innerHTML = html;
  }).catch(function() {});
}

function renderFinal(final, st) {
  document.getElementById('finalSection').style.display = '';
  var html = '';
  if (final.low_bar_status) {
    var sCls = final.low_bar_status === 'pass' ? 'green' : (final.low_bar_status === 'blocked' ? 'red' : 'orange');
    html += '<span class="final-badge ' + sCls + '">' + final.low_bar_status + '</span>';
  }
  if (st.feasibility_report && st.feasibility_report.verdict) {
    var fCls = st.feasibility_report.verdict === 'feasible' ? 'green' : (st.feasibility_report.verdict === 'risky' ? 'orange' : 'red');
    html += '<span class="final-badge ' + fCls + '">可行性: ' + st.feasibility_report.verdict + ' (' + st.feasibility_report.score + '分)</span>';
  }
  if (st.review_report && st.review_report.overall_verdict) {
    var rCls = st.review_report.overall_verdict === 'ACCEPT' ? 'green' : (st.review_report.overall_verdict === 'MINOR_REVISION' ? 'orange' : 'red');
    html += '<span class="final-badge ' + rCls + '">审查: ' + st.review_report.overall_verdict + '</span>';
  }
  if (final.summary) html += '<div style="margin-top:6px">' + final.summary + '</div>';
  if (!html) html = '<div style="color:#94a3b8">无最终推荐</div>';
  document.getElementById('finalReport').innerHTML = html;
}

function viewCase(caseId) {
  if (!caseId) return;
  initStateMachine();
  setProgress(TOTAL_NODES);
  // Mark all nodes as done
  document.querySelectorAll('.state-node').forEach(function(n) { n.classList.add('done'); });
  fetchAndRenderAll(caseId);
  document.getElementById('statusBar').textContent = '查看历史: ' + caseId;
}

var uploadedPapers = [];
var currentCaseId = null;

function uploadPaper() {
  var title = document.getElementById('uploadTitle').value.trim();
  var doi = document.getElementById('uploadDoi').value.trim();
  var arxiv = document.getElementById('uploadArxiv').value.trim();
  var role = document.getElementById('uploadRole').value;
  if (!title && !doi && !arxiv) { alert('请至少输入标题、DOI 或 arXiv ID'); return; }
  if (!currentCaseId) { currentCaseId = genCaseId(); }
  document.getElementById('uploadTitle').value = '';
  document.getElementById('uploadDoi').value = '';
  document.getElementById('uploadArxiv').value = '';
  fetch('/api/v1/research/' + currentCaseId + '/papers', {
    method: 'POST', headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({title: title, doi: doi, arxiv_id: arxiv, role: role})
  }).then(function(r) { return r.json(); }).then(function(d) {
    if (d.paper) {
      uploadedPapers.push(d.paper);
      renderUploadList();
    }
  }).catch(function(e) { alert('上传失败: ' + e); });
}

function renderUploadList() {
  var html = '';
  for (var i = 0; i < uploadedPapers.length; i++) {
    var p = uploadedPapers[i];
    var tag = p.arxiv_id ? 'arXiv:' + p.arxiv_id : (p.doi ? 'DOI:' + p.doi : 'title');
    html += '<div style="font-size:12px;padding:3px 0;color:#059669;">✓ ' + (p.title || tag) + ' <span style="color:#94a3b8">[' + (p.role || 'baseline') + ']</span></div>';
  }
  document.getElementById('uploadList').innerHTML = html || '<div style="font-size:12px;color:#cbd5e1;">暂无上传论文</div>';
}

// Init
initStateMachine();
loadHistory();
renderUploadList();
</script>
