function renderOptimization(st) {
  var opts = st.optimization_directions || {};
  if (!opts || Object.keys(opts).length === 0) return;
  document.getElementById('optimizationSection').style.display = '';
  var html = '';
  // Optimization paths
  var paths = opts.optimization_paths || opts.directions || [];
  if (paths.length > 0) {
    html += '<h4 style="font-size:12px;color:#475569;margin-bottom:4px;">优化路径 (' + paths.length + ')</h4><ul style="list-style:none;padding:0;">';
    for (var i = 0; i < paths.length; i++) {
      var d = paths[i];
      var dir = d.direction || d.title || ('路径 ' + (i+1));
      var gain = d.expected_gain || '';
      var diff = d.difficulty || '';
      var items = d.action_items || [];
      html += '<li style="margin-bottom:6px;"><b>' + dir + '</b>';
      if (gain) html += '<br><span style="color:#16a34a;font-size:11px;">预期增益: ' + gain + '</span>';
      if (diff) html += ' <span style="color:#f59e0b;font-size:11px;">难度: ' + diff + '</span>';
      if (items.length > 0) {
        html += '<ul style="font-size:11px;color:#64748b;padding-left:20px;">';
        for (var j = 0; j < items.length; j++) html += '<li>' + items[j] + '</li>';
        html += '</ul>';
      }
      html += '</li>';
    }
    html += '</ul>';
  }
  // Degradation paths
  var degr = opts.degradation_paths || [];
  if (degr.length > 0) {
    html += '<h4 style="font-size:12px;color:#475569;margin:6px 0 4px;">降级路径 (' + degr.length + ')</h4><ul style="list-style:none;padding:0;">';
    for (var i = 0; i < degr.length; i++) {
      var d = degr[i];
      html += '<li style="margin-bottom:4px;font-size:11px;"><b>' + (d.path||'') + '</b>';
      if (d.trade_off) html += ' <span style="color:#ef4444;">代价: ' + d.trade_off + '</span>';
      if (d.survival_rate) html += ' <span style="color:#64748b;">存活率: ' + d.survival_rate + '</span>';
      html += '</li>';
    }
    html += '</ul>';
  }
  // Risk mitigation
  var risks = opts.risk_mitigation || [];
  if (risks.length > 0) {
    html += '<h4 style="font-size:12px;color:#475569;margin:6px 0 4px;">风险缓解</h4><ul style="font-size:11px;color:#475569;padding-left:20px;">';
    for (var i = 0; i < risks.length; i++) html += '<li>' + risks[i] + '</li>';
    html += '</ul>';
