<body>

<div class="top-bar">
  <h1>PaperAgent</h1>
  <div class="input-group">
    <input type="text" id="topic" placeholder="输入研究题目...">
    <button id="startBtn" onclick="startResearch()">开始研究</button>
  </div>
  <select id="historySelect" onchange="viewCase(this.value)">
    <option value="">— 历史 Case —</option>
  </select>
</div>

<!-- User paper upload (Re3.1) -->
<div class="papers-panel" id="uploadPanel" style="margin-bottom:8px;">
  <div class="panel-title">上传已知论文 (可选)</div>
  <div style="display:flex;gap:6px;flex-wrap:wrap;margin-top:4px;">
    <input type="text" id="uploadTitle" placeholder="论文标题" style="flex:1;min-width:120px;padding:6px 8px;border:1px solid #d0d0d0;border-radius:6px;font-size:13px;">
    <input type="text" id="uploadDoi" placeholder="DOI (可选)" style="width:120px;padding:6px 8px;border:1px solid #d0d0d0;border-radius:6px;font-size:13px;">
    <input type="text" id="uploadArxiv" placeholder="arXiv ID (可选)" style="width:120px;padding:6px 8px;border:1px solid #d0d0d0;border-radius:6px;font-size:13px;">
    <select id="uploadRole" style="padding:6px 8px;border:1px solid #d0d0d0;border-radius:6px;font-size:13px;">
      <option value="baseline">baseline</option>
      <option value="parallel">parallel</option>
    </select>
    <button onclick="uploadPaper()" style="padding:6px 14px;background:#059669;color:#fff;border:none;border-radius:6px;cursor:pointer;font-size:13px;">添加</button>
  </div>
  <div id="uploadList" style="margin-top:6px;"></div>
</div>
<div id="statusBar" class="status-bar"></div>
<div class="progress-bar"><div id="progressFill" class="progress-fill"></div></div>

<!-- State machine panel -->
<div class="state-machine">
  <div class="sm-title">状态机 <span id="smProgress" style="float:right;font-weight:400">0/0</span></div>
  <div class="state-track" id="stateTrack"></div>
</div>

<!-- Panels row: connectivity + candidate counts -->
<div class="panels-row">
  <div class="panel" style="flex:1;max-width:340px;">
    <div class="panel-title">连通性</div>
    <div id="connPanel">
      <div class="conn-item"><span class="conn-name"><span class="conn-dot pending"></span> DeepSeek</span><span class="conn-latency">—</span></div>
      <div class="conn-item"><span class="conn-name"><span class="conn-dot pending"></span> OpenAlex</span><span class="conn-latency">—</span></div>
      <div class="conn-item"><span class="conn-name"><span class="conn-dot pending"></span> Crossref</span><span class="conn-latency">—</span></div>
      <div class="conn-item"><span class="conn-name"><span class="conn-dot pending"></span> arXiv</span><span class="conn-latency">—</span></div>
      <div class="conn-item"><span class="conn-name"><span class="conn-dot pending"></span> GitHub</span><span class="conn-latency">—</span></div>
      <div class="conn-item"><span class="conn-name"><span class="conn-dot pending"></span> S2 API</span><span class="conn-latency">—</span></div>
    </div>
  </div>
  <div class="panel" style="flex:1;">
    <div class="panel-title">候选</div>
    <div class="count-grid" id="countGrid">
      <div class="count-item"><span class="count-label">Papers</span><span class="count-num" id="cnt-papers">0</span></div>
      <div class="count-item"><span class="count-label">Repos</span><span class="count-num" id="cnt-repos">0</span></div>
      <div class="count-item"><span class="count-label">Datasets</span><span class="count-num" id="cnt-datasets">0</span></div>
      <div class="count-item"><span class="count-label">Surveys</span><span class="count-num" id="cnt-surveys">0</span></div>
      <div class="count-item"><span class="count-label">Expanded</span><span class="count-num" id="cnt-expanded">0</span></div>
      <div class="count-item"><span class="count-label">Seeds</span><span class="count-num" id="cnt-seeds">0</span></div>
    </div>
  </div>
</div>

<!-- Paper list -->
<div class="papers-panel" id="papersPanel" style="display:none;">
  <div class="panel-title">论文列表</div>
  <div id="paperList"></div>
</div>

<!-- Collapsed results -->
<details class="results-section" id="evidenceSection" style="display:none;">
  <summary>证据图谱</summary>
  <div class="results-content" id="evidenceGraph"></div>
</details>

<details class="results-section" id="wpSection" style="display:none;">
  <summary>工作包</summary>
