  'low_bar_review': 'review', 'optimization_advisor': 'optimize',
  'devils_advocate': 'devils', 'human_gate': 'human',
  'final_recommendation': 'final',
};
function _resolveNodeName(nodeName) {
  return NODE_NAME_MAP[nodeName] || nodeName;
}

function genCaseId() { return 're24-' + Date.now().toString(36); }

function setProgress(n) {
  var pct = Math.min(100, Math.round(n / TOTAL_NODES * 100));
  document.getElementById('progressFill').style.width = pct + '%';
  document.getElementById('smProgress').textContent = n + '/' + TOTAL_NODES;
}

function initStateMachine() {
  var track = document.getElementById('stateTrack');
  var html = '';
  for (var i = 0; i < NODE_NAMES.length; i++) {
    if (i > 0) html += '<span class="state-arrow">›</span>';
    html += '<span class="state-node" data-idx="' + i + '" data-name="' + NODE_NAMES[i] + '">' + NODE_NAMES[i] + '</span>';
  }
  track.innerHTML = html;
  nodeProgress = 0;
  setProgress(0);
}

