function fetchAndRenderAll(caseId) {
  fetch('/api/v1/research/' + caseId + '/state').then(function(r) { return r.json(); }).then(function(st) {
    allPapers = [];
    var vp = st.verified_papers || [];
    var wp = st.weak_papers || [];
    for (var i = 0; i < vp.length; i++) allPapers.push(vp[i]);
    for (var i = 0; i < wp.length; i++) allPapers.push(wp[i]);
    renderPapers();
    renderEvidenceGraph(st);
    renderWorkPackages(st.work_packages || []);
    renderNarrative(st);
    renderInnovation(st);
    renderSota(st);
    renderOptimization(st);
    renderTrace(caseId);
    renderFinal(st.final_recommendation || {}, st);
    // Update counts from final state
    setCount('cnt-papers', (st.verified_papers || []).length + (st.weak_papers || []).length);
    setCount('cnt-repos', (st.repo_candidates || []).length);
    setCount('cnt-datasets', (st.dataset_candidates || []).length);
    setCount('cnt-surveys', (st.surveys_found || []).length);
    setCount('cnt-expanded', (st.expanded_papers || []).length);
    setCount('cnt-seeds', (st.seed_papers || []).length);
  }).catch(function() {});
}

function renderPapers() {
  document.getElementById('papersPanel').style.display = '';
  var html = '';
  for (var i = 0; i < allPapers.length; i++) {
    var p = allPapers[i];
    var verdict = p.verdict || 'unknown';
    var cls = verdict === 'accept' ? 'accept' : (verdict === 'weak_reject' ? 'weak' : 'reject');
    var icon = verdict === 'accept' ? '✓' : (verdict === 'weak_reject' ? '⚠' : '✗');
    var title = (p.title || '').substring(0, 80);
    var rel = p.relation_to_topic || '';
    var uploadTag = p.source === 'user_upload' ? ' <span style="color:#059669;font-size:10px;">[用户上传]</span>' : '';
    html += '<div class="paper-card ' + cls + '">';
    html += '<span class="verdict-icon">' + icon + '</span>';
    html += '<div class="paper-body">';
    html += '<div class="paper-title">' + title + uploadTag + '</div>';
    if (rel) html += '<div class="paper-rel">' + rel + '</div>';
    html += '</div></div>';
  }
  document.getElementById('paperList').innerHTML = html || '<div style="color:#94a3b8;font-size:13px;padding:8px;">无论文</div>';
}

function renderEvidenceGraph(st) {
  document.getElementById('evidenceSection').style.display = '';
  var groups = [
    {label: 'Baseline', items: st.baseline_candidates || []},
    {label: 'Parallel', items: st.parallel_candidates || []},
    {label: 'Survey', items: (st.surveys || []).concat(st.surveys_found || [])},
    {label: 'Dataset', items: st.dataset_candidates || []},
    {label: 'Repo', items: (st.repo_candidates || []).concat(st.repos_found || [])}
  ];
  var html = '';
  for (var g = 0; g < groups.length; g++) {
    var items = groups[g].items;
    html += '<div class="eg-group"><div class="eg-group-title">' + groups[g].label + ' (' + items.length + ')</div>';
    for (var i = 0; i < Math.min(items.length, 10); i++) {
      var title = items[i].title || items[i].name || items[i].url || '';
      html += '<div class="eg-item">' + (title.substring(0, 80) || '') + '</div>';
    }
    if (items.length > 10) html += '<div class="eg-item">... 还有 ' + (items.length - 10) + ' 条</div>';
    html += '</div>';
  }
  document.getElementById('evidenceGraph').innerHTML = html;
}

function renderWorkPackages(wps) {
  document.getElementById('wpSection').style.display = '';
  var html = '';
  for (var i = 0; i < wps.length; i++) {
    var wp = wps[i];
    var title = wp.title || wp.approach || wp.name || ('工作包 ' + (i + 1));
    var desc = wp.description || wp.summary || '';
    html += '<div class="wp-item"><b>' + (i + 1) + '. ' + title + '</b>';
    if (desc) html += '<br><span style="color:#64748b">' + desc.substring(0, 200) + '</span>';
    html += '</div>';
  }
  document.getElementById('workPackages').innerHTML = html || '<div style="color:#94a3b8;font-size:13px">无工作包</div>';
}

function renderNarrative(st) {
  var n = st.research_narrative || st.research_narratives || {};
  if (!n || Object.keys(n).length === 0) return;
  document.getElementById('narrativeSection').style.display = '';
  var html = '';
  var fields = [
    ['three_problems', '三个核心问题'], ['nick_model_name', '模型命名'],
    ['narrative_summary', '叙事总结'], ['chapter_outline', '章节大纲'],
    ['abstract_draft', '摘要草稿'], ['research_gap', '研究空白'],
    ['proposed_approach', '拟用方案'], ['contribution', '预期贡献'],
    ['methodology', '方法论'], ['risks', '风险'], ['summary', '总结']
  ];
  for (var i = 0; i < fields.length; i++) {
    var v = n[fields[i][0]];
    if (v) {
      var vs = typeof v === 'string' ? v : JSON.stringify(v, null, 2);
      html += '<div style="margin-bottom:6px;"><b>' + fields[i][1] + ':</b> ' + vs.substring(0, 500) + '</div>';
    }
  }
  if (!html) html = '<div style="color:#94a3b8">无叙事数据</div>';
  document.getElementById('narrativeContent').innerHTML = html;
}

function renderInnovation(st) {
  var pts = st.innovation_points || [];
  if (pts.length === 0) return;
  document.getElementById('innovationSection').style.display = '';
  var html = '<ul style="list-style:none;padding:0;">';
  for (var i = 0; i < pts.length; i++) {
    var p = pts[i];
    var desc = p.description || p.title || p.name || ('创新点 ' + (i+1));
    var baseline = p.baseline_used || '';
    var modules = p.stitched_modules || [];
    var plan = p.stitching_plan || '';
    var diff = p.estimated_difficulty || '';
    html += '<li style="margin-bottom:8px;padding-bottom:4px;border-bottom:1px solid #f1f5f9;">';
    html += '<b>创新点 ' + (i+1) + '</b>: ' + desc;
    if (baseline) html += '<br><span style="color:#64748b;font-size:11px;">基线: ' + baseline + '</span>';
    if (modules.length > 0) html += '<br><span style="color:#64748b;font-size:11px;">缝合模块: ' + modules.join(' + ') + '</span>';
    if (plan) html += '<br><span style="color:#64748b;font-size:11px;">缝合方案: ' + (typeof plan === 'string' ? plan.substring(0,200) : JSON.stringify(plan).substring(0,200)) + '</span>';
    if (diff) html += '<br><span style="color:#f59e0b;font-size:11px;">难度: ' + diff + '</span>';
    html += '</li>';
  }
  html += '</ul>';
  if (st.stitching_plan) {
    var sp = st.stitching_plan;
    html += '<div style="margin-top:6px;padding:6px;background:#f8fafc;border-radius:4px;"><b>总体缝合方案:</b><br>';
    html += '<span style="font-size:11px;color:#64748b;">基线模型: ' + (sp.baseline_model||'') + '</span><br>';
    html += '<span style="font-size:11px;color:#64748b;">模块B: ' + (sp.module_b||'') + '</span><br>';
    html += '<span style="font-size:11px;color:#64748b;">模块C: ' + (sp.module_c||'') + '</span>';
    if (sp.stitching_steps) {
      html += '<br><b style="font-size:11px;">缝合步骤:</b><ol style="font-size:11px;color:#475569;padding-left:20px;">';
      for (var s = 0; s < sp.stitching_steps.length; s++) {
        html += '<li>' + sp.stitching_steps[s].substring(0, 200) + '</li>';
      }
      html += '</ol>';
    }
    html += '</div>';
  }
  document.getElementById('innovationContent').innerHTML = html;
}

function renderSota(st) {
  var s = st.sota_comparison || {};
  if (!s || Object.keys(s).length === 0) return;
  document.getElementById('sotaSection').style.display = '';
  var html = '';
  // Comparison papers table
  var papers = s.comparison_papers || s.comparison || [];
  if (papers.length > 0) {
    html += '<h4 style="font-size:12px;color:#475569;margin-bottom:4px;">对比论文 (' + papers.length + ')</h4>';
    html += '<table style="width:100%;font-size:11px;border-collapse:collapse;">';
    html += '<tr style="border-bottom:1px solid #e2e8f0;"><th style="text-align:left;padding:3px;">标题</th><th style="text-align:left;padding:3px;">年份</th></tr>';
    for (var i = 0; i < Math.min(papers.length, 10); i++) {
      var p = papers[i];
      html += '<tr style="border-bottom:1px solid #f8fafc;"><td style="padding:3px;">' + (p.title||'').substring(0, 60) + '</td><td style="padding:3px;">' + (p.year||'') + '</td></tr>';
    }
    html += '</table>';
  }
  // Metrics
  var metrics = s.metrics_to_compare || [];
  if (metrics.length > 0) {
    html += '<h4 style="font-size:12px;color:#475569;margin:6px 0 4px;">对比指标</h4><div style="font-size:11px;color:#475569;">' + metrics.join(', ') + '</div>';
  }
  // Ablation suggestions
  var ablations = s.ablation_suggestions || [];
  if (ablations.length > 0) {
    html += '<h4 style="font-size:12px;color:#475569;margin:6px 0 4px;">消融实验建议</h4><ul style="font-size:11px;color:#475569;padding-left:20px;">';
    for (var i = 0; i < ablations.length; i++) {
      var a = ablations[i];
      html += '<li>' + (a.name||'') + ': ' + (a.purpose||'') + '</li>';
    }
    html += '</ul>';
  }
  // Experiment checklist
  var checklist = s.experiment_checklist || [];
  if (checklist.length > 0) {
    html += '<h4 style="font-size:12px;color:#475569;margin:6px 0 4px;">实验检查清单</h4><ul style="font-size:11px;color:#475569;padding-left:20px;">';
    for (var i = 0; i < checklist.length; i++) {
      html += '<li>' + checklist[i] + '</li>';
    }
    html += '</ul>';
  }
  // Fallback for other field structures
  if (s.current_sota) html += '<div style="margin-bottom:4px;"><b>当前 SOTA:</b> ' + s.current_sota + '</div>';
  if (s.gap) html += '<div style="margin-bottom:4px;"><b>差距:</b> ' + s.gap + '</div>';
  if (!html) html = '<div style="color:#94a3b8">无 SOTA 数据</div>';
  document.getElementById('sotaContent').innerHTML = html;
}

function renderOptimization(st) {
  var opts = st.optimization_directions || {};
  if (!opts || Object.keys(opts).length === 0) return;
  document.getElementById('optimizationSection').style.display = '';
  var html = '';
  // Optimization paths
  var paths = opts.optimization_paths || opts.directions || [];
  if (paths.length > 0) {
    html += '<h4 style="font-size:12px;color:#475569;margin-bottom:4px;">优化路径 (' + paths.length + ')</h4><ul style="list-style:none;padding:0;">';
    for (var i = 0; i < paths.length; i++) {
      var d = paths[i];
      var dir = d.direction || d.title || ('路径 ' + (i+1));
      var gain = d.expected_gain || '';
      var diff = d.difficulty || '';
      var items = d.action_items || [];
      html += '<li style="margin-bottom:6px;"><b>' + dir + '</b>';
      if (gain) html += '<br><span style="color:#16a34a;font-size:11px;">预期增益: ' + gain + '</span>';
      if (diff) html += ' <span style="color:#f59e0b;font-size:11px;">难度: ' + diff + '</span>';
      if (items.length > 0) {
        html += '<ul style="font-size:11px;color:#64748b;padding-left:20px;">';
        for (var j = 0; j < items.length; j++) html += '<li>' + items[j] + '</li>';
        html += '</ul>';
      }
      html += '</li>';
    }
    html += '</ul>';
  }
  // Degradation paths
  var degr = opts.degradation_paths || [];
  if (degr.length > 0) {
    html += '<h4 style="font-size:12px;color:#475569;margin:6px 0 4px;">降级路径 (' + degr.length + ')</h4><ul style="list-style:none;padding:0;">';
    for (var i = 0; i < degr.length; i++) {
      var d = degr[i];
      html += '<li style="margin-bottom:4px;font-size:11px;"><b>' + (d.path||'') + '</b>';
      if (d.trade_off) html += ' <span style="color:#ef4444;">代价: ' + d.trade_off + '</span>';
      if (d.survival_rate) html += ' <span style="color:#64748b;">存活率: ' + d.survival_rate + '</span>';
      html += '</li>';
    }
    html += '</ul>';
  }
  // Risk mitigation
  var risks = opts.risk_mitigation || [];
  if (risks.length > 0) {
    html += '<h4 style="font-size:12px;color:#475569;margin:6px 0 4px;">风险缓解</h4><ul style="font-size:11px;color:#475569;padding-left:20px;">';
    for (var i = 0; i < risks.length; i++) html += '<li>' + risks[i] + '</li>';
    html += '</ul>';
  }
  if (opts.summary) html += '<div style="margin-top:4px;">' + opts.summary + '</div>';
  if (!html) html = '<div style="color:#94a3b8">无优化建议</div>';
  document.getElementById('optimizationContent').innerHTML = html;
}

function renderTrace(caseId) {
  fetch('/api/v1/research/' + caseId + '/trace').then(function(r) { return r.json(); }).then(function(trace) {
    if (!trace || trace.length === 0) return;
    document.getElementById('traceSection').style.display = '';
    var html = '';
    for (var i = 0; i < trace.length; i++) {
      var ev = trace[i];
      var node = ev.node || ev.step || '';
      var msg = ev.output_summary ? JSON.stringify(ev.output_summary) : (ev.input_summary ? JSON.stringify(ev.input_summary) : '');
      var prov = ev.provider || '';
      var cls = prov === 'heuristic' ? 'color:#f59e0b' : 'color:#475569';
      html += '<div style="padding:3px 0;border-bottom:1px solid #f8fafc;font-size:11px;">';
      html += '<span style="color:#94a3b8;">[' + (i+1) + ']</span> ';
      html += '<b style="' + cls + '">' + node + '</b> ';
      if (prov) html += '<span style="color:#cbd5e1;">(' + prov + ')</span> ';
      if (ev.elapsed_s) html += '<span style="color:#94a3b8;">' + ev.elapsed_s + 's</span> ';
      if (msg) html += '<span style="color:#64748b;">' + msg.substring(0, 120) + '</span>';
      html += '</div>';
    }
    document.getElementById('traceContent').innerHTML = html;
  }).catch(function() {});
}

function renderFinal(final, st) {
  document.getElementById('finalSection').style.display = '';
  var html = '';
  if (final.low_bar_status) {
    var sCls = final.low_bar_status === 'pass' ? 'green' : (final.low_bar_status === 'blocked' ? 'red' : 'orange');
    html += '<span class="final-badge ' + sCls + '">' + final.low_bar_status + '</span>';
  }
  if (st.feasibility_report && st.feasibility_report.verdict) {
    var fCls = st.feasibility_report.verdict === 'feasible' ? 'green' : (st.feasibility_report.verdict === 'risky' ? 'orange' : 'red');
    html += '<span class="final-badge ' + fCls + '">可行性: ' + st.feasibility_report.verdict + ' (' + st.feasibility_report.score + '分)</span>';
  }
  if (st.review_report && st.review_report.overall_verdict) {
    var rCls = st.review_report.overall_verdict === 'ACCEPT' ? 'green' : (st.review_report.overall_verdict === 'MINOR_REVISION' ? 'orange' : 'red');
    html += '<span class="final-badge ' + rCls + '">审查: ' + st.review_report.overall_verdict + '</span>';
  }
  if (final.summary) html += '<div style="margin-top:6px">' + final.summary + '</div>';
  if (!html) html = '<div style="color:#94a3b8">无最终推荐</div>';
  document.getElementById('finalReport').innerHTML = html;
}

function viewCase(caseId) {
  if (!caseId) return;
  initStateMachine();
  setProgress(TOTAL_NODES);
  // Mark all nodes as done
  document.querySelectorAll('.state-node').forEach(function(n) { n.classList.add('done'); });
  fetchAndRenderAll(caseId);
  document.getElementById('statusBar').textContent = '查看历史: ' + caseId;
}

var uploadedPapers = [];
var currentCaseId = null;

function uploadPaper() {
  var title = document.getElementById('uploadTitle').value.trim();
  var doi = document.getElementById('uploadDoi').value.trim();
  var arxiv = document.getElementById('uploadArxiv').value.trim();
  var role = document.getElementById('uploadRole').value;
  if (!title && !doi && !arxiv) { alert('请至少输入标题、DOI 或 arXiv ID'); return; }
  if (!currentCaseId) { currentCaseId = genCaseId(); }
  document.getElementById('uploadTitle').value = '';
  document.getElementById('uploadDoi').value = '';
  document.getElementById('uploadArxiv').value = '';
  fetch('/api/v1/research/' + currentCaseId + '/papers', {
    method: 'POST', headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({title: title, doi: doi, arxiv_id: arxiv, role: role})
  }).then(function(r) { return r.json(); }).then(function(d) {
    if (d.paper) {
      uploadedPapers.push(d.paper);
      renderUploadList();
    }
  }).catch(function(e) { alert('上传失败: ' + e); });
}

function renderUploadList() {
  var html = '';
  for (var i = 0; i < uploadedPapers.length; i++) {
    var p = uploadedPapers[i];
    var tag = p.arxiv_id ? 'arXiv:' + p.arxiv_id : (p.doi ? 'DOI:' + p.doi : 'title');
    html += '<div style="font-size:12px;padding:3px 0;color:#059669;">✓ ' + (p.title || tag) + ' <span style="color:#94a3b8">[' + (p.role || 'baseline') + ']</span></div>';
  }
  document.getElementById('uploadList').innerHTML = html || '<div style="font-size:12px;color:#cbd5e1;">暂无上传论文</div>';
}

// Init
initStateMachine();
loadHistory();
renderUploadList();
</script>
</body>
